class LightweightNotificationSystem{constructor(options={}){this.userId=options.userId;this.pollInterval=options.pollInterval||30000;this.isSSESupported=typeof(EventSource)!=="undefined";this.isVisible=true;this.pollTimer=null;this.lastNotificationId=0;this.init();this.setupVisibilityDetection()}init(){if(this.isSSESupported&&!this.isSharedHosting()){this.startSSE()}else{this.startPolling()}}isSharedHosting(){return window.location.hostname.includes('hostinger')||window.location.hostname.includes('shared')}startSSE(){const eventSource=new EventSource(`/notifications/stream?user_id=${this.userId}`);eventSource.onmessage=(event)=>{const data=JSON.parse(event.data);this.processNotifications(data)};eventSource.onerror=()=>{console.log('SSE failed,falling back to polling');eventSource.close();this.startPolling()}}startPolling(){this.pollForNotifications();this.pollTimer=setInterval(()=>{if(this.isVisible){this.pollForNotifications()}},this.pollInterval)}async pollForNotifications(){try{const response=await fetch(`/notifications/get-new?user_id=${this.userId}&last_id=${this.lastNotificationId}`);const data=await response.json();if(data.success&&data.notifications.length>0){this.processNotifications(data.notifications);this.lastNotificationId=Math.max(...data.notifications.map(n=>n.id))}}catch(error){console.error('Polling error:',error)}}processNotifications(notifications){notifications.forEach(notification=>{this.showNotification(notification);this.updateNotificationBadge()})}showNotification(notification){this.showToast(notification);this.addToDropdown(notification);this.playNotificationSound()}showToast(notification){const toast=document.createElement('div');toast.className='notification-toast';toast.innerHTML=`<div class="toast-content"><i class="fas fa-${notification.icon||'bell'}toast-icon"></i><div class="toast-text"><strong>${notification.title}</strong><p>${notification.message}</p></div><button class="toast-close" onclick="this.parentElement.parentElement.remove()">×</button></div>`;document.body.appendChild(toast);setTimeout(()=>{if(toast.parentElement){toast.remove()}},5000)}setupVisibilityDetection(){document.addEventListener('visibilitychange',()=>{this.isVisible=!document.hidden;if(this.isVisible){this.pollForNotifications();if(this.pollTimer){this.pollInterval=30000}}else{this.pollInterval=120000}})}updateNotificationBadge(){fetch(`/notifications/count?user_id=${this.userId}`).then(response=>response.json()).then(data=>{const badge=document.getElementById('notificationBadge');const countElement=document.querySelector('.notification-count');if(data.count>0){badge.style.display='inline';countElement.textContent=data.count}else{badge.style.display='none'}})}addToDropdown(notification){const dropdown=document.getElementById('notificationDropdownMenu');const notificationHtml=`<li class="notification-item" data-id="${notification.id}"><a class="dropdown-item" href="${notification.url||'#'}" onclick="markAsRead(${notification.id})"><div class="d-flex"><div class="notification-icon"><i class="fas fa-${notification.icon||'bell'}"></i></div><div class="notification-content"><div class="notification-title">${notification.title}</div><div class="notification-message">${notification.message}</div><div class="notification-time">${this.formatTime(notification.created_at)}</div></div></div></a></li>`;dropdown.insertAdjacentHTML('afterbegin',notificationHtml)}playNotificationSound(){const audio=new Audio('data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmAaBT2a1/L');audio.volume=0.3;audio.play().catch(()=>{})}formatTime(dateString){const date=new Date(dateString);const now=new Date();const diffMinutes=Math.floor((now-date)/60000);if(diffMinutes<1)return 'Baru saja';if(diffMinutes<60)return `${diffMinutes}menit lalu`;const diffHours=Math.floor(diffMinutes/60);if(diffHours<24)return `${diffHours}jam lalu`;const diffDays=Math.floor(diffHours/24);return `${diffDays}hari lalu`}}document.addEventListener('DOMContentLoaded',function(){if(typeof userId !=='undefined'){window.notificationSystem=new LightweightNotificationSystem({userId:userId,pollInterval:30000})}});function markAsRead(notificationId){fetch(`/notifications/mark-read/${notificationId}`,{method:'POST',headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest'}}).then(()=>{document.querySelector(`[data-id="${notificationId}"]`).style.opacity='0.5';window.notificationSystem.updateNotificationBadge()})}function markAllAsRead(){fetch('/notifications/mark-all-read',{method:'POST',headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest'}}).then(()=>{document.querySelectorAll('.notification-item').forEach(item=>{item.style.opacity='0.5'});window.notificationSystem.updateNotificationBadge()})}